import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;

@Service
public class ZerodhaOrderMetricsService {
    private final MeterRegistry registry;

    ZerodhaOrderMetricsService(MeterRegistry registry) {
        this.registry = registry;
    }

    public void recordSubmission(String type, String symbol) {
        // Create or look up the counter for this tag combination:
        registry.counter("orders.submitted",
            "type", type,          // BUY or SELL (2 values — low cardinality OK)
            "symbol", symbol       // NIFTY, BANKNIFTY, SENSEX — manageable
        ).increment();
    }

    public void recordRejection(String reason) {
        registry.counter("orders.rejected",
            "reason", reason       // insufficient_funds, invalid_symbol, market_closed
        ).increment();
    }

    // WHY SYMBOL MUST BE LOW CARDINALITY:
    // NSE has 1,500+ stocks. If symbol = 'INFY', 'TCS', 'RELIANCE', ...
    // → 1,500+ unique time series in Prometheus
    // Better: use index categories: 'NIFTY50', 'MIDCAP', 'SMALLCAP'
    // Worst: symbol = specific stock code → manageable
    // Never: symbol = full ISIN 'INE009A01021' (too many unique values)
    //
    // Rule: if a tag can have > 100 distinct values → reconsider
    // If > 1000 → definitely wrong, use logs instead
}

import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;

@Service
public class RazorpayPaymentTimer {
    private final MeterRegistry registry;

    RazorpayPaymentTimer(MeterRegistry registry) {
        this.registry = registry;
    }

    public PaymentResult processPayment(String gateway, PaymentRequest req) {
        // Create or get timer by gateway:
        Timer timer = Timer.builder("payment.processing.time")
            .tag("gateway", gateway)
            .publishPercentiles(0.5, 0.95, 0.99)
            .register(registry);

        return timer.record(() -> {
            // Simulated payment processing:
            try {
                Thread.sleep(100 + (long)(Math.random() * 200));  // 100-300ms
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            return new PaymentResult(req.id(), "APPROVED");
        });
    }

    public long getCallCount(String gateway) {
        return registry.find("payment.processing.time")
            .tag("gateway", gateway)
            .timer()
            .map(Timer::count)
            .orElse(0L);
    }

    record PaymentRequest(String id) {}
    record PaymentResult(String id, String status) {}
}

