import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentLinkedQueue;

@Service
public class SwiggyResourceGauges {

    SwiggyResourceGauges(
            MeterRegistry registry,
            Queue<Object> retryQueue,
            SimulatedHikariPool pool,
            SimulatedCaffeineCache cache) {

        // GAUGE: tracks the current value of a thing that changes over time
        Gauge.builder("payment.retry.queue.size", retryQueue, Collection::size)
            .description("Payment requests waiting for retry")
            .register(registry);

        Gauge.builder("db.connection.pool.active", pool, SimulatedHikariPool::getActiveConnections)
            .description("Active DB connections")
            .tag("pool", "HikariPool-1")
            .register(registry);

        Gauge.builder("cache.memory.entries", cache, SimulatedCaffeineCache::estimatedSize)
            .description("Estimated cache entries")
            .tag("cache", "products")
            .register(registry);
    }

    // WHY GAUGE NOT COUNTER:
    // Counter: orders processed = 14,523 (always growing — correct for count)
    // Queue size: starts at 0, grows as retries added, shrinks as retries succeed
    //   → Counter would only go UP — can't track shrinking
    //   → Gauge reflects the CURRENT real-time value
    // Pool active: can be 0, 15, 50, 50, 42, 8 throughout the day
    //   → Only Gauge can represent 'current' point-in-time values

    // Gauge takes a reference to the object + a function to read the value:
    // Gauge.builder(name, object, valueFunction)
    // Micrometer calls valueFunction.apply(object) each time it's read

    interface SimulatedHikariPool { int getActiveConnections(); }
    interface SimulatedCaffeineCache { long estimatedSize(); }
}

import io.micrometer.core.annotation.Timed;
import org.springframework.stereotype.Service;

@Service
public class BookMyShowTicketService {

    // @Timed: Spring AOP proxy wraps the method and records duration
    // Requires: spring-boot-starter-aop AND @EnableAspectJAutoProxy

    @Timed(
        value = "ticket.booking.time",
        description = "Time to complete ticket booking",
        percentiles = {0.5, 0.95, 0.99},
        extraTags = {"service", "booking"}  // additional tags
    )
    public String bookTicket(String eventId, String seatId) {
        // ... booking logic ...
        return "BOOKING-" + System.currentTimeMillis();
    }

    @Timed(value = "seat.availability.check.time")
    public boolean checkAvailability(String eventId, String seatId) {
        // ... check logic ...
        return true;
    }

    // @Timed vs manual Timer.builder():
    //
    // @Timed (annotation-driven):
    //   + Simple: one annotation, no boilerplate
    //   + Works on any @Service/@Component method
    //   - Limited control: fixed tag values (can't use runtime values as tags)
    //   - Can't tag by method result (success/failure requires try-catch in Timer)
    //
    // Manual Timer.builder() + timer.record():
    //   + Full control: tag by status, gateway, exception type
    //   + Can time subsections of a method
    //   + Can conditionally record (only record slow calls)
    //   - More code
    //
    // Use @Timed for: simple method timing with static tags
    // Use manual for: business metrics with dynamic tags (status, user type, gateway)
}

