@Component("visaGateway")
public class VisaGatewayHealthIndicator implements HealthIndicator {
    private final VisaConnectivityCheck visaCheck;

    VisaGatewayHealthIndicator(VisaConnectivityCheck c) { visaCheck = c; }

    @Override
    public Health health() {
        try {
            long start = System.currentTimeMillis();
            boolean connected = visaCheck.ping();
            long latencyMs = System.currentTimeMillis() - start;

            if (connected) {
                return Health.up()
                    .withDetail("latencyMs", latencyMs)
                    .withDetail("gateway", "visa")
                    .build();
            } else {
                return Health.down()
                    .withDetail("reason", "Visa gateway not responding")
                    .withDetail("gateway", "visa")
                    .build();
            }
        } catch (Exception e) {
            return Health.down(e)
                .withDetail("gateway", "visa")
                .build();
        }
    }

    // GET /actuator/health:
    // {
    //   "status": "UP",
    //   "components": {
    //     "visaGateway": {
    //       "status": "UP",
    //       "details": { "latencyMs": 45, "gateway": "visa" }
    //     }
    //   }
    // }

    interface VisaConnectivityCheck { boolean ping(); }
}

import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;

@Service
public class PaymentAmountMetrics {
    private final DistributionSummary amountSummary;

    PaymentAmountMetrics(MeterRegistry registry) {
        amountSummary = DistributionSummary.builder("payment.amount")
            .baseUnit("rupees")
            .description("Distribution of payment amounts in INR")
            .publishPercentiles(0.5, 0.95, 0.99)
            .minimumExpectedValue(1.0)    // minimum ₹1
            .maximumExpectedValue(100000.0)  // maximum ₹1 lakh
            .register(registry);
    }

    public void record(double amountInr) {
        amountSummary.record(amountInr);
    }

    public DistributionSummary.HistogramSnapshot snapshot() {
        return amountSummary.takeSnapshot();
    }

    // DistributionSummary vs Timer:
    // Timer: measures DURATION (time). Unit: nanoseconds internally.
    // DistributionSummary: measures arbitrary VALUES. Unit: you define (rupees, bytes, items).
    //
    // Use DistributionSummary for:
    //   payment amounts (₹): range ₹1 to ₹1,00,000
    //   response body size (bytes)
    //   items in cart
    //   download speed (MB/s)
    //
    // Use Timer for:
    //   API response time
    //   DB query time
    //   External API call duration

    public static void main(String[] a) {
        System.out.println("DistributionSummary: track value distributions (amounts, sizes)");
        System.out.println("Timer: track duration distributions (latency)");
    }
}

