@Service
class RazorpayPaymentMetricsService {
    private final MeterRegistry reg;
    private final Queue<String> retryQueue = new ConcurrentLinkedQueue<>();
    private final Map<String, Timer> timers = new ConcurrentHashMap<>();

    RazorpayPaymentMetricsService(MeterRegistry r) {
        reg = r;
        Gauge.builder("payments.retry.queue.size", retryQueue, Collection::size)
             .register(reg);
    }

    private Timer getTimer(String gateway) {
        return timers.computeIfAbsent(gateway, gw ->
            Timer.builder("payments.duration")
                 .tag("gateway", gw)
                 .publishPercentiles(0.5, 0.95, 0.99)
                 .register(reg));
    }

    public String processPayment(String gateway, String merchantType, double amount) {
        return getTimer(gateway).record(() -> {
            String status;
            try {
                Thread.sleep(50);
                status = "success";
                reg.counter("payments.total",
                    "status", status, "gateway", gateway, "merchant_type", merchantType
                ).increment();
                DistributionSummary.builder("payments.amount")
                    .tag("gateway", gateway).baseUnit("rupees")
                    .register(reg).record(amount);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                status = "failure";
                reg.counter("payments.total",
                    "status", status, "gateway", gateway, "merchant_type", merchantType
                ).increment();
            }
            return "PAY-" + System.currentTimeMillis();
        });
    }

    public Queue<String> getRetryQueue() { return retryQueue; }
}

