import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import java.util.concurrent.atomic.AtomicInteger;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ZerodhaOrderMetrics {
    private final MeterRegistry reg;
    private final AtomicInteger processingQueue = new AtomicInteger(0);
    private final Timer buyTimer, sellTimer;

    ZerodhaOrderMetrics(MeterRegistry r) {
        reg = r;
        buyTimer  = Timer.builder("orders.execution.time").tag("type","BUY" ).publishPercentiles(0.5,0.95,0.99).register(reg);
        sellTimer = Timer.builder("orders.execution.time").tag("type","SELL").publishPercentiles(0.5,0.95,0.99).register(reg);
        Gauge.builder("orders.queue.depth", processingQueue, AtomicInteger::get)
             .description("Orders currently being processed").register(reg);
    }

    public void submitted(String type, String segment) {
        reg.counter("orders.submitted","type",type,"segment",segment).increment();
    }

    public void rejected(String reason) {
        reg.counter("orders.rejected","reason",reason).increment();
    }

    public String executeOrder(String type, String segment) {
        processingQueue.incrementAndGet();
        try {
            Timer t = "BUY".equals(type) ? buyTimer : sellTimer;
            return t.record(() -> {
                submitted(type, segment);
                try { Thread.sleep(20); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
                return "ORD-" + System.currentTimeMillis();
            });
        } finally {
            processingQueue.decrementAndGet();
        }
    }
}

@SpringBootTest
class ZerodhaOrderMetricsTest {
    @Autowired ZerodhaOrderMetrics metrics;
    @Autowired MeterRegistry reg;

    @Test void submitted_counter_increments() {
        metrics.executeOrder("BUY","EQUITY");
        Counter c=reg.find("orders.submitted").tag("type","BUY").tag("segment","EQUITY").counter();
        assertNotNull(c); assertTrue(c.count()>=1);
    }
    @Test void rejection_counter_works() {
        metrics.rejected("insufficient_funds");
        Counter c=reg.find("orders.rejected").tag("reason","insufficient_funds").counter();
        assertNotNull(c); assertTrue(c.count()>=1);
    }
    @Test void timer_records_execution_time() {
        metrics.executeOrder("SELL","FNO");
        Timer t=reg.find("orders.execution.time").tag("type","SELL").timer();
        assertNotNull(t); assertTrue(t.count()>=1);
    }
}

