import io.micrometer.core.instrument.*;
import io.micrometer.core.instrument.config.MeterFilter;
import io.micrometer.core.instrument.MeterRegistry;
import org.springframework.boot.actuate.autoconfigure.metrics.MeterRegistryCustomizer;
import org.springframework.context.annotation.*;

@Configuration
public class MeterFilterConfig {

    // MeterRegistryCustomizer: applied to the global MeterRegistry at startup
    @Bean
    public MeterRegistryCustomizer<MeterRegistry> metricsCommonTags() {
        return registry -> registry
            .config()
            // Filter 1: add region tag to ALL meters:
            .meterFilter(MeterFilter.commonTags(
                Tags.of("region", "india", "datacenter", "mumbai")
            ))
            // Filter 2: rename jvm.* to zerodha.jvm.*:
            .meterFilter(MeterFilter.renameMetric("jvm", "zerodha.jvm"))
            // Filter 3: deny any metric with 'test' in the name:
            .meterFilter(new MeterFilter() {
                @Override
                public MeterFilter.MeterFilterReply accept(Meter.Id id) {
                    if (id.getName().contains("test")) {
                        return MeterFilter.MeterFilterReply.DENY;
                    }
                    return MeterFilter.MeterFilterReply.NEUTRAL;
                }
            });
    }

    // WHY MeterFilter BEATS MANUAL TAGS:
    // Without MeterFilter:
    //   Every Counter.builder() needs .tag("region", "india")
    //   Every Timer.builder() needs .tag("region", "india")
    //   Forget one: metric missing region tag → Grafana query returns partial data
    //
    // With MeterFilter.commonTags():
    //   Set once at startup
    //   Applied to ALL meters (including 3rd-party library meters!)
    //   JVM, Hikari, Resilience4j metrics all get 'region=india'
    //
    // Alternative: management.metrics.tags.region=india in application.yml
    //   (equivalent, but MeterFilter allows conditional logic)

    public static void main(String[] a) {
        System.out.println("MeterFilter: apply tags/renames/denies globally to all meters");
    }
}

