@Service
class RazorpayFullMetrics {
    private final MeterRegistry reg;
    private final AtomicInteger activePayments = new AtomicInteger(0);
    private final Timer payTimer;
    private final DistributionSummary amtSummary;

    RazorpayFullMetrics(MeterRegistry r) {
        reg=r;
        payTimer=Timer.builder("rp.payment.duration").publishPercentiles(0.5,0.95,0.99).register(reg);
        amtSummary=DistributionSummary.builder("rp.payment.amount").baseUnit("rupees").register(reg);
        Gauge.builder("rp.payments.active",activePayments,AtomicInteger::get).register(reg);
    }

    public String process(String gateway, double amount) {
        activePayments.incrementAndGet();
        try {
            return payTimer.record(()->{
                reg.counter("rp.payments.total","status","success","gateway",gateway).increment();
                amtSummary.record(amount);
                return "PAY-"+System.currentTimeMillis();
            });
        } finally { activePayments.decrementAndGet(); }
    }
}

